// src/components/PropertyFilter.js
import React, { useState } from 'react';

const PropertyFilter = ({ onFilter, onClear, loading }) => {
  const [filters, setFilters] = useState({
    minPrice: '',
    maxPrice: '',
    bedrooms: '',
    city: ''
  });
  const [error, setError] = useState('');

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFilters(prev => ({
      ...prev,
      [name]: value
    }));
    setError('');
  };

  const handleClear = () => {
    setFilters({
      minPrice: '',
      maxPrice: '',
      bedrooms: '',
      city: ''
    });
    setError('');
    if (onClear) onClear();
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    const minPrice = filters.minPrice ? parseFloat(filters.minPrice) : null;
    const maxPrice = filters.maxPrice ? parseFloat(filters.maxPrice) : null;

    if (minPrice && maxPrice && minPrice > maxPrice) {
      setError('Min price should be less than max price.');
      return;
    }

    setError('');
    if (onFilter) {
      onFilter({
        minPrice,
        maxPrice,
        bedrooms: filters.bedrooms ? parseInt(filters.bedrooms, 10) : null,
        city: filters.city || null
      });
    }
  };

  return (
    <div className="property-filter" style={{ padding: '20px', border: '1px solid #ddd', borderRadius: '8px' }}>
      <form onSubmit={handleSubmit}>
        <div>
          <label htmlFor="minPrice">Minimum Price</label>
          <input
            id="minPrice"
            type="number"
            name="minPrice"
            value={filters.minPrice}
            onChange={handleChange}
          />
        </div>
        <div>
          <label htmlFor="maxPrice">Maximum Price</label>
          <input
            id="maxPrice"
            type="number"
            name="maxPrice"
            value={filters.maxPrice}
            onChange={handleChange}
          />
        </div>
        <div>
          <label htmlFor="bedrooms">Bedrooms</label>
          <input
            id="bedrooms"
            type="number"
            name="bedrooms"
            value={filters.bedrooms}
            onChange={handleChange}
          />
        </div>
        <div>
          <label htmlFor="city">City</label>
          <input
            id="city"
            type="text"
            name="city"
            value={filters.city}
            onChange={handleChange}
          />
        </div>

        <button type="submit" data-testid="filter-button">Filter</button>
        <button type="button" onClick={handleClear} data-testid="clear-button">Clear</button>
        {error && <div data-testid="filter-error">{error}</div>}
      </form>
    </div>
  );
};

export default PropertyFilter;
